const body = $json.body ?? $json;
const locale = String(body.locale || 'en').toLowerCase().startsWith('ar') ? 'ar' : 'en';
const useCase = String(body.use_case || body.preset || 'custom').trim() || 'custom';
const preset = useCase;
const details = String(body.details || body.prompt || body.message || '').trim();
const prompt = String(body.prompt || body.message || details).trim();
const source = String(body.source || 'landing').trim() || 'landing';
const historyRaw = body.history;
let history = [];
if (Array.isArray(historyRaw)) history = historyRaw;
else if (typeof historyRaw === 'string') { try { history = JSON.parse(historyRaw); } catch (_) { history = []; } }
const sessionId = String(body.session_id || '').trim();
let route = 'ok';
let errorMessage = null;
if (!sessionId) { route = 'bad_request'; errorMessage = 'session_id is required'; }
else if (!prompt) { route = 'bad_request'; errorMessage = 'prompt or details is required'; }
return {
  json: {
    session_id: sessionId,
    locale,
    use_case: useCase,
    preset,
    source,
    details,
    prompt,
    history: Array.isArray(history) ? history.slice(-4) : [],
    model: 'openai/gpt-oss-20b',
    route,
    error_message: errorMessage
  }
};

const history = Array.isArray($json.history) ? $json.history : [];
const historyLines = history.length
  ? history.map((item, index) => `${index + 1}. ${item.role === 'assistant' ? 'assistant' : 'user'}: ${String(item.content || '').trim()}`).join('\n')
  : 'None';
const systemPrompt = [
  'You design concise AI agent blueprints for business automation MVPs.',
  'Return valid JSON only. No markdown. No prose outside JSON.',
  'Required keys: agent_name, business_goal, workflow, example_output, roi, suggested_stack, next_step.',
  'Workflow must have 4 to 6 steps. suggested_stack must have 3 to 6 items.',
  'Keep output practical, short, and implementation-minded.',
  'Prefer n8n, Groq, CRM, messaging, scheduling, reporting tools when relevant.'
].join(' ');
const userPrompt = [
  `Locale: ${$json.locale}`,
  `Use case: ${$json.use_case || $json.preset || 'custom'}`,
  `Preset: ${$json.preset || 'custom'}`,
  `Source: ${$json.source || 'landing'}`,
  'Recent context:',
  historyLines,
  'Business task details:',
  $json.details || $json.prompt,
  'Prompt fallback:',
  $json.prompt,
  'Need one production-minded AI agent blueprint for landing page MVP.'
].join('\n');
return {
  json: {
    ...$json,
    request_body: {
      model: $json.model,
      temperature: 0.2,
      max_tokens: 700,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      response_format: {
        type: 'json_schema',
        json_schema: {
          name: 'ai_agent_blueprint',
          strict: true,
          schema: {
            type: 'object',
            additionalProperties: false,
            required: ['agent_name','business_goal','workflow','example_output','roi','suggested_stack','next_step'],
            properties: {
              agent_name: { type: 'string' },
              business_goal: { type: 'string' },
              workflow: { type: 'array', minItems: 4, maxItems: 6, items: { type: 'string' } },
              example_output: { type: 'string' },
              roi: { type: 'string' },
              suggested_stack: { type: 'array', minItems: 3, maxItems: 6, items: { type: 'string' } },
              next_step: { type: 'string' }
            }
          }
        }
      }
    }
  }
};

